<script setup lang="ts">import {currentLanguage} from "../../services/LanguageService.ts";import TitleBar from "../../components/TitleBar.vue";import ThemeEditor from "./components/ThemeEditor.vue";import ThemePreview from "./components/ThemePreview.vue";import {getCustomTheme, saveCustomTheme} from "../../store/CustomThemeConfig.ts";import {applyPreviewThemeToDOM, forbidCalculate, themeConfig} from "./composables/ThemeEditorDataComposable.ts";import {useMessage} from "naive-ui";import {computed, onMounted, ref, watch} from "vue";import {themes} from "../../services/ThemeService.ts";import {open, save} from "@tauri-apps/plugin-dialog";import {readTextFile, writeTextFile} from "@tauri-apps/plugin-fs";import {invoke} from "@tauri-apps/api/core";import {emit} from "@tauri-apps/api/event";const message = useMessage();// 预设主题选择const selectBasicTheme = ref('');const themeOptions = themes.value.filter(t => t.id !== 'custom').map(t => {  return {value: t.id, label: currentLanguage.value.pages.list.menu[t.id]}});const showThemeText = computed(() => {  return currentLanguage.value.pages.list.menu[selectBasicTheme.value] || '选择主题';})// 主题导出完成const exportSuccessModalVisible = ref(false);const exportFilePath = ref('');/** * 导入主题 */async function onImport() {  console.log("导入主题");  const filePath = await open({    multiple: false,    directory: false,    title: currentLanguage.value.pages.settings.themeEditor.themeImport,    filters: [{      name: '主题文件',      extensions: ['epth']    }]  });  console.log("文件路径", filePath)  if (!filePath) {    return;  }  const msg = message.loading('主题文件解析中', {    duration: 0  })  try {    const data = await readTextFile(filePath);    Object.assign(themeConfig, JSON.parse(data));  } catch (e) {    message.error('主题文件解析失败');  } finally {    msg.destroy();  }}/** * 导出主题 */async function onExport() {  console.log("导出主题");  const filePath = await save({    defaultPath: 'customTheme',    title: currentLanguage.value.pages.settings.themeEditor.themeExport,    filters: [{      name: '主题文件',      extensions: ['epth']    }],    canCreateDirectories: true  })  if (!filePath) {    return;  }  console.log("文件路径", filePath)  const msg = message.loading('主题数据导出中', {    duration: 0  })  await writeTextFile(filePath, JSON.stringify(themeConfig));  msg.destroy();  exportSuccessModalVisible.value = true;  exportFilePath.value = filePath;  console.log('主题数据导出完成');}/** * 显示文件所在位置 */async function onShowFile() {  exportSuccessModalVisible.value = false;  await invoke('open_folder', {path: exportFilePath.value})}/** * 重置主题 */async function onReset() {  console.log("重置主题");  forbidCalculate.value = true;  selectBasicTheme.value = '';  const oldTheme = await getCustomTheme();  Object.assign(themeConfig, oldTheme.colors);  applyPreviewThemeToDOM(themeConfig);  message.success('主题设置重置完成');}/** * 保存主题 */async function saveTheme() {  console.log("保存主题", themeConfig)  await saveCustomTheme(themeConfig);  await emit("reload-custom-theme");  message.success('保存成功')}watch(selectBasicTheme, (themeId) => {  const theme = themes.value.find(t => t.id === themeId);  if (theme) {    forbidCalculate.value = true;    Object.assign(themeConfig, JSON.parse(JSON.stringify(theme.colors)));    applyPreviewThemeToDOM(themeConfig);  }})onMounted(async () => {  // 初始化自定义主题  const theme = await getCustomTheme();  forbidCalculate.value = true;  Object.assign(themeConfig, theme.colors);  console.log("主页面加载完成")})</script><template>  <titleBar      :title="currentLanguage.pages.settings.themeEditor.title"      :showCloseBtn="true"      :dev-tool="`theme-editor`"  />  <!-- 按钮行 -->  <div class="editor-content">    <div class="operation-line">      <n-popselect v-model:value="selectBasicTheme" :options="themeOptions" trigger="click">        <n-button>{{ showThemeText }}</n-button>      </n-popselect>      <n-button @click="onImport">导入</n-button>      <n-button @click="onExport">导出</n-button>      <n-button @click="onReset">重置</n-button>      <n-button type="primary" @click="saveTheme">保存</n-button>    </div>    <!-- 主题编辑/预览 -->    <n-split direction="horizontal" style="height: 100%" :max="0.65" :min="0.35">      <template #1>        <!-- 颜色设置区域 -->        <theme-editor/>      </template>      <template #2>        <!-- 颜色预览区域 -->        <theme-preview/>      </template>    </n-split>    <!-- 主题导出完成确认框 -->    <n-modal v-model:show="exportSuccessModalVisible" title="主题导出完成" preset="dialog" :closable="false">      <span>主题文件已保存至：{{ exportFilePath }}</span>      <template #action>        <n-button @click="onShowFile">打开文件所在位置</n-button>        <n-button type="primary" @click="exportSuccessModalVisible = false">关闭</n-button>      </template>    </n-modal>  </div></template><style scoped>.editor-content {  width: 100%;  height: calc(100vh - 25px);  display: flex;  flex-direction: column;}.operation-line {  display: flex;  justify-content: flex-end;  gap: 5px;  border-bottom: 1px solid var(--theme-universal-border);  padding: 5px 10px;}</style>